const patterns = $input.all().map(i => i.json);
const results = [];

for (const p of patterns) {
  const occurrences = parseInt(p.occurrence_count||0);
  const engagements = parseInt(p.engagement_count||0);
  const timesReopened = parseInt(p.times_reopened||0);
  const timesFixed = parseInt(p.times_fixed||0);

  // Determine pattern type
  let patternType = 'recurring';
  let narrative = '';

  if (engagements >= 3 && timesFixed > 0 && timesReopened > 0) {
    patternType = 'systemic';
    narrative = `${p.cwe_id} (${p.category}) has appeared in ${engagements} engagements for ${p.client_name}. Despite ${timesFixed} fix attempt(s), it has reopened ${timesReopened} time(s), indicating a systemic weakness in the development process.`;
  } else if (engagements >= 2) {
    patternType = 'recurring';
    narrative = `${p.cwe_id} (${p.category}) has recurred across ${engagements} engagements for ${p.client_name}. Pattern suggests this vulnerability class is not being addressed at root cause.`;
  } else {
    patternType = 'emerging';
    narrative = `${p.cwe_id} (${p.category}) first detected for ${p.client_name}. Monitor for recurrence.`;
  }

  results.push({
    client_id: p.client_id,
    category: p.category,
    cwe_id: p.cwe_id,
    owasp_category: p.owasp_category,
    occurrence_count: occurrences,
    engagement_count: engagements,
    first_seen: p.first_seen,
    last_seen: p.last_seen,
    pattern_type: patternType,
    narrative
  });
}

// Build summary for Slack
const systemic = results.filter(r => r.pattern_type === 'systemic');
const recurring = results.filter(r => r.pattern_type === 'recurring');

const slackSummary = [
  `📊 *RECON OS — Weekly Weakness Heatmap*`,
  `Date: ${new Date().toISOString().split('T')[0]}`,
  `Patterns analyzed: ${results.length}`,
  systemic.length > 0 ? `\n🔴 *SYSTEMIC (${systemic.length})*:` : '',
  ...systemic.slice(0,3).map(s => `  • ${s.cwe_id} — ${s.client_id} — ${s.engagement_count} engagements, reopened ${s.occurrence_count}×`),
  recurring.length > 0 ? `\n🟡 *RECURRING (${recurring.length})*:` : '',
  ...recurring.slice(0,3).map(r => `  • ${r.cwe_id} (${r.category}) — ${r.engagement_count} engagements`)
].filter(Boolean).join('\n');

return [{ json: { patterns: results, slack_summary: slackSummary, systemic_count: systemic.length, total: results.length } }];
